func ShouldThrottle() bool {
throttling := atomic.Load(&bm.throttling)
lag := CalculateLag()
if throttling {
// Use LOWER threshold to stop
if lag < LagThresholdLow {
atomic.Store(&bm.throttling, 0)
return false  // STOP
}
return true  // Continue
} else {
// Use HIGHER threshold to start
if lag > LagThresholdHigh {
atomic.Store(&bm.throttling, 1)
return true  // START
}
return false  // Continue
}
}
